// runAutoRefresh invokes the API-backed sync for the stale resources.
// Refresh failures are non-fatal; the command proceeds with the stale cache.
func runAutoRefresh(ctx context.Context, flags *rootFlags, _ []string) error {
	cfg, err := config.Load(flags.configPath)
	if err != nil {
		return fmt.Errorf("load config: %w", err)
	}
	alClient := anylist.New(cfg)
	userData, err := alClient.GetUserData(ctx)
	if err != nil {
		return fmt.Errorf("fetch user data: %w", err)
	}
	st, err := store.Open(cfg)
	if err != nil {
		return fmt.Errorf("open store: %w", err)
	}
	defer st.Close()
	if err := st.SyncFromUserData(userData); err != nil {
		return err
	}
	for _, r := range defaultSyncResources {
		_ = st.SaveSyncState(r)
	}
	return nil
}

// ensureFreshForResources lets hand-authored commands participate in the same
// freshness hook as generated resource commands. Custom commands should call
// this before reading from the store, then use wrapWithProvenance for JSON
// output if they want meta.freshness.
func ensureFreshForResources(ctx context.Context, flags *rootFlags, resources ...string) cliutil.FreshnessMeta {
	meta := autoRefreshIfStale(ctx, flags, resources)
	flags.freshnessMeta = meta
	return meta
}
